// ============================================================
// Compare the last two rows from the Google Sheets crawl data
// and build a prompt + Anthropic API request body.
//
// Output: { requestBody, project, previousDate, currentDate, changesCount }
// ============================================================

const items = $input.all();

if (items.length < 2) {
  throw new Error(`Need at least 2 rows to compare, got ${items.length}`);
}

// Last two rows — most recent crawl results
const prev = items[items.length - 2].json;
const curr = items[items.length - 1].json;

// All column headers present in the data
const headers = Object.keys(curr);

// Metadata columns (not compared as metrics)
const metadataColumns = ['Project', 'URL', 'Audit Date', 'row_number'];
const metricColumns = headers.filter(h => !metadataColumns.includes(h));

// ---- Compute diffs ----
const changes = [];
for (const col of metricColumns) {
  const prevVal = prev[col];
  const currVal = curr[col];
  if (String(prevVal ?? '').trim() !== String(currVal ?? '').trim()) {
    const entry = { column: col, previous: prevVal, current: currVal };
    const pNum = parseFloat(prevVal);
    const cNum = parseFloat(currVal);
    if (!isNaN(pNum) && !isNaN(cNum) && prevVal !== '' && currVal !== '') {
      entry.diff = cNum - pNum;
      entry.pctChange = pNum !== 0
        ? ((cNum - pNum) / pNum * 100).toFixed(1) + '%'
        : 'N/A';
    }
    changes.push(entry);
  }
}

// ---- Format data for Claude ----
const fmt = (row) => headers
  .filter(h => h !== 'row_number')
  .map(h => `  ${h}: ${row[h] ?? 'N/A'}`)
  .join('\n');

const changeSummary = changes.length > 0
  ? changes.map(c => {
      let line = `  ${c.column}: ${c.previous} \u2192 ${c.current}`;
      if (c.diff !== undefined) {
        line += ` (${c.diff >= 0 ? '+' : ''}${c.diff}, ${c.pctChange})`;
      }
      return line;
    }).join('\n')
  : '  No changes detected between the two crawls.';

const userPrompt = [
  `Crawl comparison for ${curr['Project'] || 'tracked website'} (${curr['URL'] || ''}).`,
  '',
  `PREVIOUS CRAWL (${prev['Audit Date'] || 'unknown date'}):`,
  fmt(prev),
  '',
  `LATEST CRAWL (${curr['Audit Date'] || 'unknown date'}):`,
  fmt(curr),
  '',
  `CHANGES (${changes.length} fields):`,
  changeSummary,
  '',
  'Produce the daily crawl report.'
].join('\n');

const systemPrompt = [
  'You are an SEO monitoring analyst. You receive daily website crawl data',
  'comparisons and produce concise, actionable Telegram reports.',
  '',
  'Report structure:',
  '1. Header: \"\ud83d\udcca *SEO Crawl Report \u2014 [project]*\" + date range',
  '2. Status line: \u2705 Stable / \u26a0\ufe0f Changes detected / \ud83d\udea8 Issues found',
  '3. Key metrics with deltas: Audit Score, SEO Score, total Crawled URLs',
  '4. URL status breakdown: success, errors, 404s, redirects, timeouts, forbidden',
  '5. Crawl depth distribution shifts (only if notable)',
  '6. One-line takeaway or action item if warranted',
  '',
  'Formatting:',
  '- Telegram Markdown: *bold*, `code`',
  '- Show direction: \u2191 increase, \u2193 decrease',
  '- Under 2000 characters',
  '- Be direct, no filler'
].join('\n');

const requestBody = {
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 2048,
  system: systemPrompt,
  messages: [{ role: 'user', content: userPrompt }]
};

return [{
  json: {
    requestBody,
    project: curr['Project'] || 'unknown',
    previousDate: prev['Audit Date'] || 'unknown',
    currentDate: curr['Audit Date'] || 'unknown',
    changesCount: changes.length
  }
}];
